mapper.insert:
INSERT INTO analytics_chat_session (
    user_id, report_key, view_id, view_name, title, context_json
) VALUES (
    #{userId}, #{reportKey}, #{viewId}, #{viewName}, #{title}, #{contextJson}
)

mapper.update:
UPDATE analytics_chat_session
SET title = #{title}, updated_at = NOW()
WHERE id = #{id} AND user_id = #{userId}

UPDATE analytics_chat_session
SET context_json = #{contextJson}, updated_at = NOW()
WHERE id = #{id} AND user_id = #{userId}

mapper.select:
SELECT * FROM analytics_chat_session
WHERE id = #{id} AND user_id = #{userId}
LIMIT 1

SELECT * FROM analytics_chat_session
WHERE user_id = #{userId}
  AND report_key = #{reportKey}
  AND view_id = #{viewId}
ORDER BY updated_at DESC
LIMIT #{limit}
